import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;

class Calculator {
    int add(int a, int b) {
        return a + b;
    }
}

public class CalculatorTest {
    @Test
    void testAddition() {
        Calculator calc = new Calculator();
        int result = calc.add(2, 3);
        assertEquals(5, result, "2 + 3 should equal 5");
    }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

class BankAccount {
    private double balance;
    public BankAccount(double balance) { this.balance = balance; }
    public void withdraw(double amount) {
        if (amount > balance) throw new IllegalArgumentException("Insufficient funds");
        balance -= amount;
    }
}

public class BankAccountTest {
    private BankAccount account;

    @BeforeEach
    void setUp() {
        account = new BankAccount(100.0);
    }

    @Test
    void testWithdrawalSuccess() {
        account.withdraw(40.0);
        // Assuming a getter exists, or we test behavior
    }

    @Test
    void testWithdrawalExceedsBalanceThrowsException() {
        Exception exception = assertThrows(IllegalArgumentException.class, () -> {
            account.withdraw(150.0);
        });
        assertEquals("Insufficient funds", exception.getMessage());
    }
}

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

interface PaymentGateway {
    boolean processPayment(double amount);
}

class OrderService {
    private PaymentGateway gateway;
    public OrderService(PaymentGateway gateway) { this.gateway = gateway; }
    public String checkout(double amount) {
        if (gateway.processPayment(amount)) return "Success";
        else return "Failed";
    }
}

public class OrderServiceTest {
    @Test
    void testCheckoutSuccess() {
        // Create a mock of the dependency
        PaymentGateway mockGateway = mock(PaymentGateway.class);

        // Define the behavior of the mock
        when(mockGateway.processPayment(50.0)).thenReturn(true);

        // Inject the mock into the class under test
        OrderService service = new OrderService(mockGateway);

        // Act & Assert
        assertEquals("Success", service.checkout(50.0));

        // Verify interaction (optional but good practice)
        verify(mockGateway, times(1)).processPayment(50.0);
    }
}

